(function(){"use strict";document.querySelectorAll(".blog-interactive-checklist").forEach(function(r){var t="nt-checklist-"+(document.location.pathname||"blog").replace(/\W+/g,"-").slice(0,80);try{var n=JSON.parse(sessionStorage.getItem(t)||"{}");r.querySelectorAll('input[type="checkbox"]').forEach(function(e,o){var c=e.id||t+"-item-"+o;e.id||(e.id=c),n[c]&&(e.checked=!0),e.addEventListener("change",function(){try{var i=JSON.parse(sessionStorage.getItem(t)||"{}");i[c]=e.checked,sessionStorage.setItem(t,JSON.stringify(i))}catch(a){}})})}catch(e){}})})();
